#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(a,b,c) for(int c=a.head[(b)];c;c=a.nxt[c])
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e6+10,M=2e6+10,Mod=19260817;
struct Graph
{
	int head[N],des[M],nxt[M],col[M],cnt;
	inline void ins(int x,int y,int z){nxt[++cnt]=head[x];des[head[x]=cnt]=y;col[cnt]=z;}
	inline void Init(){memset(head,0,sizeof(head));cnt=1;}
}a;

int fa[N];inline int find(int x){return fa[x]==x?x:fa[x]=find(fa[x]);}
int n,m,K;int lst[N],siz[N];bool vis[N<<1];long long ans;
map<int,int>mp[N];
pair<int,int> que[N];int H=1,T;
inline void merge(int u,int v)
{
//	printf("caonmdbdeshabi %d %d\n",u,v);
	int x=find(u),y=find(v);if(x==y)return;
	if(mp[x].size()<mp[y].size()){int tmp=y;y=x;x=tmp;}
	for(auto i: mp[y])
	{
		int tmp=mp[x][i.first];
		if(tmp)que[++T]=make_pair(tmp,i.second);
		else mp[x][i.first]=i.second;
	}
	fa[y]=x;siz[x]+=siz[y];mp[y].clear();
}
inline void Solve(){while(H<=T){merge(que[H].first,que[H].second);++H;}}
int main()
{
	n=read();m=read();K=read();a.Init();
	rep(1,m,i)
	{
		int y=read(),x=read(),z=read(),tmp;
		if((tmp=mp[x][z]))que[++T]=make_pair(tmp,y);
		else mp[x][z]=y;
	}
//	rep(H,T,i)printf("i : %d %d\n",que[i].first,que[i].second);
	rep(1,n,i)fa[i]=i,siz[i]=1;Solve();
//	rep(1,n,i)printf("%d ",find(i));puts("");
	rep(1,n,i)
	{
		int rt=find(i);//printf("%d %d\n",rt,siz[rt]);
		if(!vis[rt])ans+=1ll*siz[rt]*(siz[rt]-1)>>1;
		vis[rt]=1;
	}
	printf("%lld\n",ans);
}
